function jv_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function jv_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function jv_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function jv_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function jv_c($v){return strtoupper(trim((string)$v));}
function jv_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function jv_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function jv_next_no($year){global $db;$year=(int)$year>0?(int)$year:(int)date('Y');$r=$db->fetch("SELECT vacancy_no FROM erp_job_vacancy WHERE vacancy_no LIKE ? ORDER BY vacancy_no DESC LIMIT 1",array('JV-'.$year.'-%'));$n=1;if($r&&preg_match('/-(\d+)$/',$r->vacancy_no,$m))$n=(int)$m[1]+1;return 'JV-'.$year.'-'.str_pad($n,3,'0',STR_PAD_LEFT);}
function jv_row($id){
  global $db;
  return $db->fetch("SELECT v.*,mp.plan_no,mp.plan_name,p.position_code,p.position_name,jt.job_title_code,jt.job_title_name,d.nm_dept,cs.structure_code,cs.structure_name,cc.cost_center_name,pc.profit_center_name,wl.location_code,wl.location_name,rec.employee_no recruiter_no,rec.full_name recruiter_name,hm.employee_no manager_no,hm.full_name manager_name
    FROM erp_job_vacancy v
    LEFT JOIN erp_manpower_plan mp ON mp.id=v.manpower_plan_id
    LEFT JOIN erp_position p ON p.id=v.position_id
    LEFT JOIN erp_job_title jt ON jt.id=v.job_title_id
    LEFT JOIN dept d ON d.kd_dept=v.department_code
    LEFT JOIN erp_company_structure cs ON cs.id=v.company_structure_id
    LEFT JOIN erp_cost_center cc ON cc.cost_center_code=v.cost_center_code
    LEFT JOIN erp_profit_center pc ON pc.profit_center_code=v.profit_center_code
    LEFT JOIN erp_work_location wl ON wl.id=v.work_location_id
    LEFT JOIN erp_employee_master rec ON rec.id=v.recruiter_employee_id
    LEFT JOIN erp_employee_master hm ON hm.id=v.hiring_manager_employee_id
    WHERE v.id=? LIMIT 1",array((int)$id));
}
function jv_payload($r){
  $d=(array)$r;
  $d['manpower_plan_text']=$r->manpower_plan_id?($r->plan_no.' - '.$r->plan_name):'';
  $d['position_text']=$r->position_id?($r->position_code.' - '.$r->position_name):'';
  $d['job_title_text']=$r->job_title_id?($r->job_title_code.' - '.$r->job_title_name):'';
  $d['department_text']=$r->department_code?($r->department_code.' - '.$r->nm_dept):'';
  $d['company_structure_text']=$r->company_structure_id?($r->structure_code.' - '.$r->structure_name):'';
  $d['cost_center_text']=$r->cost_center_code?($r->cost_center_code.' - '.$r->cost_center_name):'';
  $d['profit_center_text']=$r->profit_center_code?($r->profit_center_code.' - '.$r->profit_center_name):'';
  $d['work_location_text']=$r->work_location_id?($r->location_code.' - '.$r->location_name):'';
  $d['recruiter_text']=$r->recruiter_employee_id?($r->recruiter_no.' - '.$r->recruiter_name):'';
  $d['hiring_manager_text']=$r->hiring_manager_employee_id?($r->manager_no.' - '.$r->manager_name):'';
  return $d;
}
function jv_export_rows($from,$to,$status,$type,$dept,$kw){
  global $db;$p=array($to,$from);$w=" WHERE COALESCE(v.posting_date,v.created_at)<=? AND COALESCE(v.closing_date,'9999-12-31')>=? ";
  if($status!==''){$w.=" AND v.vacancy_status=? ";$p[]=$status;}if($type!==''){$w.=" AND v.vacancy_type=? ";$p[]=$type;}if($dept!==''){$w.=" AND v.department_code=? ";$p[]=$dept;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (v.vacancy_no LIKE ? OR v.vacancy_title LIKE ? OR p.position_code LIKE ? OR jt.job_title_name LIKE ? OR v.sap_reference LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}
  return $db->query("SELECT v.*,mp.plan_no,p.position_code,p.position_name,jt.job_title_code,jt.job_title_name,d.nm_dept,cs.structure_code,cs.structure_name,rec.employee_no recruiter_no,rec.full_name recruiter_name,hm.employee_no manager_no,hm.full_name manager_name
    FROM erp_job_vacancy v
    LEFT JOIN erp_manpower_plan mp ON mp.id=v.manpower_plan_id
    LEFT JOIN erp_position p ON p.id=v.position_id
    LEFT JOIN erp_job_title jt ON jt.id=v.job_title_id
    LEFT JOIN dept d ON d.kd_dept=v.department_code
    LEFT JOIN erp_company_structure cs ON cs.id=v.company_structure_id
    LEFT JOIN erp_employee_master rec ON rec.id=v.recruiter_employee_id
    LEFT JOIN erp_employee_master hm ON hm.id=v.hiring_manager_employee_id
    $w ORDER BY v.created_at DESC,v.vacancy_no DESC",$p);
}

