case 'cost_center_search':$t=trim(jv_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT cost_center_code,cost_center_name FROM erp_cost_center WHERE status='Aktif' AND (?='' OR cost_center_code LIKE ? OR cost_center_name LIKE ?) ORDER BY cost_center_code LIMIT 40",array($t,$like,$like));jv_select2($rows,'cost_center_code',function($r){return $r->cost_center_code.' - '.$r->cost_center_name;});
