case 'position_search':$t=trim(jv_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,position_code,position_name,vacancy_status FROM erp_position WHERE position_status IN ('APPROVED','ACTIVE','PLANNED') AND (?='' OR position_code LIKE ? OR position_name LIKE ?) ORDER BY position_code LIMIT 40",array($t,$like,$like));jv_select2($rows,'id',function($r){return $r->position_code.' - '.$r->position_name.' ['.$r->vacancy_status.']';});
case 'work_location_search':$t=trim(jv_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,location_code,location_name,location_type FROM erp_work_location WHERE status='ACTIVE' AND (?='' OR location_code LIKE ? OR location_name LIKE ?) ORDER BY location_code LIMIT 40",array($t,$like,$like));jv_select2($rows,'id',function($r){return $r->location_code.' - '.$r->location_name.' ['.$r->location_type.']';});
