case 'save':
  $id=(int)jv_p('id');$no=jv_c(jv_p('vacancy_no'));$title=trim(jv_p('vacancy_title'));$year=(int)date('Y');if(jv_p('posting_date')!=='')$year=(int)substr(jv_p('posting_date'),0,4);if($no===''||$no==='AUTO')$no=jv_next_no($year);
