al).'</div></div><hr><div class="row"><div class="col-sm-6"><b>Job Description</b><p>'.nl2br(jv_h($r->job_description?:'-')).'</p><b>Responsibilities</b><p>'.nl2br(jv_h($r->responsibilities?:'-')).'</p></div><div class="col-sm-6"><b>Qualification</b><p>'.nl2br(jv_h($r->qualification_requirement?:'-')).'</p><b>Benefits</b><p>'.nl2br(jv_h($r->benefits?:'-')).'</p></div></div><hr><p><b>SAP Reference:</b> '.jv_h($r->sap_reference?:'-').'<br><b>Remarks:</b> '.nl2br(jv_h($r->remarks?:'-')).'</p></div>';break;
